def bump(tex, old, new):
    # match 'Figure old', 'Figures old', 'Fig. old' with optional trailing letter/subpanel, not 'Figure old0..9'
    pat = re.compile(r'\b(Figures?|Fig\.)\s+'+str(old)+r'(?![0-9])')
    return pat.sub(lambda m: f"{m.group(1)} {new}", tex)
before_counts={n:len(re.findall(r'\bFigures?\s+'+str(n)+r'(?![0-9])',tex)) for n in [1,2,3,4,5]}
for old in [5,4,3,2]:
    tex=bump(tex, old, old+1)
after_counts={n:len(re.findall(r'\bFigures?\s+'+str(n)+r'(?![0-9])',tex)) for n in [1,2,3,4,5,6]}
print("before:",before_counts)
print("after :",after_counts)
